define("tiny_justify/configuration",["editor_tiny/utils","tiny_justify/commands"],function(Utils,Commands){"use strict";const configure=instanceConfig=>{let menu=instanceConfig.menu;return menu&&menu.format&&menu.format.items&&(menu.format.items=menu.format.items.replace(/\balign(?!\w)/g,Commands.MENU_ALIGN)),{toolbar:Utils.addToolbarButtons(instanceConfig.toolbar,"content",[Commands.COMMAND_ALIGNJUSTIFY]),menu:menu,quickbars_selection_toolbar:Utils.addQuickbarsToolbarItem(instanceConfig.quickbars_selection_toolbar,Commands.COMMAND_ALIGNJUSTIFY)}};return{configure}});
